<div class="panel"><form method="post" enctype="multipart/form-data" action=""><input type="hidden" name="_csrf" value="<?= htmlspecialchars(csrf_token()) ?>"><div class="form-grid admin-form-grid"><?php foreach ($moduleDef['fields'] as $name => $field): ?><?php $value = $item[$name] ?? ''; ?><label class="<?= ($field['type'] ?? '') === 'textarea' ? 'full' : '' ?>"><span><?= htmlspecialchars($field['label']) ?></span><?php if (($field['type'] ?? '') === 'textarea'): ?><textarea name="<?= htmlspecialchars($name) ?>" rows="5"><?= htmlspecialchars((string) $value) ?></textarea><?php elseif (($field['type'] ?? '') === 'number'): ?><input type="number" name="<?= htmlspecialchars($name) ?>" value="<?= htmlspecialchars((string) $value) ?>"><?php elseif (($field['type'] ?? '') === 'date'): ?><input type="date" name="<?= htmlspecialchars($name) ?>" value="<?= htmlspecialchars((string) $value) ?>"><?php elseif (($field['type'] ?? '') === 'select'): ?><select name="<?= htmlspecialchars($name) ?>"><?php foreach (($field['options'] ?? []) as $optionValue => $optionLabel): ?><option value="<?= htmlspecialchars($optionValue) ?>" <?= (string) $value === (string) $optionValue ? 'selected' : '' ?>><?= htmlspecialchars($optionLabel) ?></option><?php endforeach; ?></select><?php elseif (($field['type'] ?? '') === 'checkbox'): ?><input type="checkbox" name="<?= htmlspecialchars($name) ?>" value="1" <?= !empty($value) ? 'checked' : '' ?>><?php elseif (($field['type'] ?? '') === 'image'): ?><?php if (!empty($value)): ?><img class="thumb-preview" src="<?= asset_url($value) ?>" alt="Preview"><?php endif; ?><input type="file" name="<?= htmlspecialchars($name) ?>" accept=".jpg,.jpeg,.png,.webp,.gif,.svg"><?php else: ?><input type="text" name="<?= htmlspecialchars($name) ?>" value="<?= htmlspecialchars((string) $value) ?>"><?php endif; ?></label><?php endforeach; ?></div><div class="form-actions"><button class="btn btn-primary" type="submit">Salvar</button><a class="btn btn-secondary" href="<?= base_url('/admin/module/' . $module) ?>">Voltar</a></div></form></div>
